export type ToolTier = 'free' | 'teaser' | 'premium';

export interface ToolPreview {
  icon: string;
  name: string;
  desc: string;
}

export interface InputField {
  key: string;
  label: string;
  type: 'text' | 'textarea' | 'file' | 'url' | 'select';
  placeholder?: string;
  required?: boolean;
  options?: { value: string; label: string }[];
}

export interface ToolConfig {
  slug: string;
  name: string;
  icon: string;
  tier: ToolTier;
  description: string;
  systemPrompt: string;
  inputFields: InputField[];
  /** Whether this tool has a custom result component (e.g. voice interview, code editor) */
  customResult?: boolean;
}

